SELECT *
  FROM admin_ad_campaign
 WHERE 1 = 1

   AND surface = #{surface}


   AND active = #{active}


   AND (
       title LIKE CONCAT('%', #{keyword}, '%')
       OR body LIKE CONCAT('%', #{keyword}, '%')
       OR placement LIKE CONCAT('%', #{keyword}, '%')
   )

 ORDER BY updated_at DESC, id DESC
 LIMIT #{limit}

mapper.insert:
INSERT INTO admin_ad_campaign (
    title, body, surface, placement, creative_type, image_url, target_url,
    visible_to_plans_json, starts_at, ends_at, priority, active, created_by, updated_by
)
VALUES (
    #{title}, #{body}, #{surface}, #{placement}, #{creativeType}, #{imageUrl}, #{targetUrl},
    CAST(#{visibleToPlansJson} AS JSON), #{startsAt}, #{endsAt}, #{priority}, #{active}, #{createdBy}, #{updatedBy}
)
